import type { Question, Subject } from '../types'

const tq = (id: string, question: string, answer: string, subject: Subject): Question => ({
  id,
  question,
  options: [],
  answer,
  explanation: '',
  subject,
})

export const THEORY_FINANCIAL_ACCOUNTING: Question[] = [
  tq('tfa1', 'Explain the accounting concepts of going concern, consistency, and accrual (matching) concept, giving the importance of each.', 'Going concern: assumes the business will continue operating indefinitely, not liquidated. Importance: justifies recording assets at cost rather than liquidation value, allows depreciation spreading. Consistency: same accounting methods applied from period to period for comparability. Importance: enables meaningful trend analysis. Accrual concept: income and expenses recorded when earned/incurred, not when cash received/paid. Importance: gives true profit position, matches revenue with related expenses. These concepts form the foundation for preparing financial statements under GAAP/IFRS.', 'Financial Accounting'),
  tq('tfa2', 'State the accounting equation and explain the effect of each of the following transactions on the equation: (i) Started business with cash N500,000 (ii) Bought goods on credit N100,000 (iii) Sold goods for cash N50,000 (cost N30,000).', 'Accounting equation: Assets = Capital + Liabilities. Effects: (i) Assets (Cash) +N500,000, Capital +N500,000. (ii) Assets (Stock) +N100,000, Liabilities (Creditors) +N100,000. (iii) Assets (Cash) +N50,000, Assets (Stock) -N30,000, Capital (Profit) +N20,000. The equation must always balance after each transaction, demonstrating double-entry principles.', 'Financial Accounting'),
  tq('tfa3', 'What is double entry bookkeeping? Record the following transactions in the ledger accounts of Suleiman: (i) Started business with cash N800,000 (ii) Bought furniture for cash N150,000 (iii) Purchased goods on credit from Bala N200,000.', 'Double entry: every transaction has two effects — a debit and a credit of equal amount. (i) Dr Cash N800,000, Cr Capital N800,000. (ii) Dr Furniture N150,000, Cr Cash N150,000. (iii) Dr Purchases N200,000, Cr Bala (Creditor) N200,000. The principle: debit what comes in/receives, credit what goes out/gives. Each transaction must balance debit and credit entries.', 'Financial Accounting'),
  tq('tfa4', 'Explain the purpose and format of a trial balance. List four types of errors that a trial balance cannot detect.', 'Trial balance: a list of all ledger balances at a date, used to verify total debits equal total credits. Purpose: detects arithmetic errors, checks ledger posting accuracy, basis for preparing financial statements. Errors not detected: (1) Error of omission — transaction completely omitted from books. (2) Error of commission — correct amount posted to wrong account of same class. (3) Error of principle — posted to wrong class of account (e.g., expense as asset). (4) Compensating errors — two errors cancel each other out. (5) Complete reversal of entries — debit posted as credit and vice versa.', 'Financial Accounting'),
  tq('tfa5', 'Prepare a trading, profit and loss account from the following trial balance of ABC Enterprises for the year ended 31/12/2023: Sales N1,500,000; Opening stock N120,000; Purchases N900,000; Closing stock N150,000; Salaries N180,000; Rent N60,000; Electricity N30,000; Advertising N20,000; Depreciation N40,000.', 'Trading Account: Sales N1,500,000 less Cost of Sales (Opening stock N120,000 + Purchases N900,000 - Closing stock N150,000 = N870,000). Gross Profit = N1,500,000 - N870,000 = N630,000. Profit & Loss: Gross Profit N630,000 less Expenses: Salaries N180,000 + Rent N60,000 + Electricity N30,000 + Advertising N20,000 + Depreciation N40,000 = N330,000. Net Profit = N630,000 - N330,000 = N300,000.', 'Financial Accounting'),
  tq('tfa6', 'Explain the three types of cash books. Record the following in a three-column cash book: opening balance N250,000; cash sales N80,000; paid supplier by cheque N45,000; received cheque from debtor N30,000; paid wages cash N15,000; bank charges N2,000.', 'Three types: single column (cash only), double column (cash and bank), three column (cash, bank, discount). Three-column cash book: Dr side: Balance b/d N250,000 (cash), Cash sales N80,000 (cash), Debtor cheque N30,000 (bank). Discount allowed column. Cr side: Supplier cheque N45,000 (bank), Wages N15,000 (cash), Bank charges N2,000 (bank). Discount received column. Balance c/d: Cash N315,000, Bank based on net bank entries.', 'Financial Accounting'),
  tq('tfa7', 'Describe the imprest system of petty cash. A petty cashier starts with N50,000. During March, payments total N38,500. The imprest is restored. How much does the petty cashier receive? Explain the entries.', 'Imprest system: a fixed amount (float) is given to the petty cashier. At the end of a period, the cashier provides receipts totalling actual expenses. The cashier is reimbursed to restore the original float. Float = N50,000. Payments = N38,500. Cash remaining = N11,500. Reimbursement = N38,500 (to restore to N50,000). Journal: Dr each expense account, Cr Cash/Bank with N38,500. The petty cash book records small payments (postage, stationery, cleaning, travel). Advantages: control over small payments, reduces main cashbook entries, separation of duties.', 'Financial Accounting'),
  tq('tfa8', 'Explain the purpose of a bank reconciliation statement. From the following, prepare a bank reconciliation: Cash book balance N120,000; Bank statement balance N135,000; Uncredited cheques N25,000; Unpresented cheques N40,000; Bank charges not in cash book N5,000; Direct debit not in cash book N10,000.', 'Bank reconciliation: explains differences between cash book and bank statement balances. Adjusted cash book balance = N120,000 - N5,000 (charges) - N10,000 (direct debit) = N105,000. Bank reconciliation: Balance per bank statement N135,000. Add: Unpresented cheques N40,000. Less: Uncredited cheques N25,000. Adjusted bank balance = N150,000. Note: adjusted cash book and adjusted bank may show the difference. Any remaining difference needs investigation (additional timing differences or errors). Bank reconciliation is an important internal control procedure.', 'Financial Accounting'),
  tq('tfa9', 'What is a control account? Prepare a sales ledger control account from: Opening debtors N200,000; Credit sales N900,000; Cash from debtors N650,000; Discount allowed N20,000; Returns inwards N30,000; Bad debts written off N15,000; Closing debtors (balancing figure).', 'Control account: a summary of individual debtor/creditor accounts, used to check accuracy of subsidiary ledgers. Sales Ledger Control Account (total debtors): Dr: Opening balance N200,000 + Credit sales N900,000 = N1,100,000. Cr: Cash received N650,000 + Discount allowed N20,000 + Returns inwards N30,000 + Bad debts N15,000 = N715,000. Closing balance (balancing figure) = N1,100,000 - N715,000 = N385,000. This should equal the total of individual debtor balances in the sales ledger.', 'Financial Accounting'),
  tq('tfa10', 'Define a suspense account and explain why it is used. Give three examples of errors corrected through a suspense account.', 'Suspense account: a temporary account used when the trial balance totals do not agree (debits do not equal credits). It holds the difference until errors are found and corrected. Examples: (1) Sales of N50,000 recorded in sales account as N5,000 — understated by N45,000. Correction: Dr Suspense N45,000, Cr Sales N45,000. (2) Discount allowed N10,000 entered on credit side of cash book — Dr Suspense N20,000, Cr Discount allowed N20,000. (3) Purchase of machinery N100,000 posted to purchases account (error of principle): Dr Machinery N100,000, Cr Purchases N100,000.', 'Financial Accounting'),
  tq('tfa11', 'Explain the methods of calculating depreciation: straight-line method and reducing balance method. A machine costs N500,000, has useful life of 5 years and residual value of N50,000. Calculate depreciation for 3 years using both methods.', 'Straight-line: (Cost - Residual)/Life = (500,000 - 50,000)/5 = N90,000 per year. Same amount each year. Reducing balance: rate = 1 - (Residual/Cost)^(1/n) which approximates 40%. Year 1: 40% x 500,000 = N200,000, NBV N300,000. Year 2: 40% x 300,000 = N120,000, NBV N180,000. Year 3: 40% x 180,000 = N72,000, NBV N108,000. Straight-line is simple; reducing balance matches higher depreciation to higher efficiency in early years.', 'Financial Accounting'),
  tq('tfa12', 'Explain the concept of bad debts and provision for doubtful debts. A business has debtors of N400,000. It decides to create a 5% provision for doubtful debts. In the next year, debtors are N500,000. Show the journal entries and ledger accounts.', 'Bad debt: a debt that is irrecoverable and written off. Provision for doubtful debts: an estimate of debts that may become bad (prudence concept). Year 1: Dr Bad debts expense (P&L) N20,000 (5% x 400,000), Cr Provision for doubtful debts N20,000. Balance sheet: Debtors N400,000 less Provision N20,000 = Net N380,000. Year 2: Required provision = 5% x 500,000 = N25,000. Existing provision = N20,000. Additional provision = N5,000. Dr Bad debts expense N5,000, Cr Provision N5,000. If provision decreases, the reduction is credited to P&L.', 'Financial Accounting'),
  tq('tfa13', 'Explain accruals and prepayments with examples. A business pays rent of N120,000 per year, paying quarterly in advance. The last payment was made on 1/12/2023 for 3 months. Prepare the rent account for the year ended 31/12/2023.', 'Accrual: expense incurred but not yet paid (liability). Prepayment: expense paid in advance (asset). Rent N120,000/year = N10,000/month. Last payment 1/12/2023 covers Dec, Jan, Feb. For year ended 31/12/2023: Rent expense = N120,000 (full year). Rent paid during year: up to 30/11 = 9 months = N90,000 plus Dec payment N30,000 = N120,000. Prepayment at 31/12/2023: Jan + Feb = N20,000 (current asset). Journal: Dr Prepaid rent N20,000, Cr Rent N20,000.', 'Financial Accounting'),
  tq('tfa14', 'Explain the concept of single entry and incomplete records. How is profit calculated under single entry?', 'Single entry: a system that does not follow full double entry — may have only personal accounts, no real/nominal accounts. Common in small businesses. Profit calculation: Opening capital (Opening net assets = Assets - Liabilities) + Additional capital - Drawings + Profit (balancing figure) = Closing capital. Rearranged: Profit = Closing capital - Opening capital + Drawings - Additional capital. Steps: (1) Calculate opening capital. (2) Calculate closing capital. (3) Apply formula. Limitations: incomplete, vulnerable to errors/fraud, difficult to prepare final accounts.', 'Financial Accounting'),
  tq('tfa15', 'From the following incomplete records, calculate profit: Opening assets: cash N50,000, stock N80,000, equipment N120,000; Opening liabilities: creditors N40,000. Closing assets: cash N60,000, stock N100,000, equipment N120,000, debtors N30,000; Closing liabilities: creditors N50,000. Drawings N60,000; Additional capital N20,000.', 'Opening capital = (50,000+80,000+120,000) - 40,000 = N210,000. Closing capital = (60,000+100,000+120,000+30,000) - 50,000 = N260,000. Increase in net assets = N50,000. Profit = Increase + Drawings - Additional capital = 50,000 + 60,000 - 20,000 = N90,000. Verification: Opening N210,000 + Profit N90,000 + Capital N20,000 - Drawings N60,000 = N260,000 = Closing capital.', 'Financial Accounting'),
  tq('tfa16', 'What is a manufacturing account? Explain its purpose and show the proforma with the main cost classifications.', 'Manufacturing account: an account that shows the cost of goods manufactured during a period. Purpose: separates production costs from other costs, shows cost of production, helps in pricing decisions. Proforma: Direct materials (Opening raw materials + Purchases - Closing raw materials) = Materials consumed. + Direct labour + Direct expenses = Prime cost. + Factory overheads (indirect materials, labour, rent, power, depreciation) + Opening WIP - Closing WIP = Factory cost (Production cost). Transferred to trading account.', 'Financial Accounting'),
  tq('tfa17', 'Explain the differences between capital expenditure and revenue expenditure. Give two examples of each and state the accounting treatment.', 'Capital expenditure: spending to acquire or improve a non-current asset that will benefit more than one accounting period. Treated as asset, depreciated over useful life. Examples: purchase of machinery, building extension. Revenue expenditure: spending for day-to-day operations, benefitting only current period. Treated as expense in P&L. Examples: repairs, rent, wages. Distinction is important — wrongly classifying capital as revenue understates profit and assets; wrongly classifying revenue as capital overstates profit and assets.', 'Financial Accounting'),
  tq('tfa18', 'Explain the concept of goodwill in partnership accounts. Describe two methods of valuing goodwill.', 'Goodwill: the intangible value of a business\'s reputation, customer relationships, brand, and earning power above its tangible assets. Arises when a partner joins, retires, or dies. Valuation methods: (1) Average profit method — Goodwill = Average profits x Number of years\' purchase. Example: Average profit of 3 years = (80,000+90,000+100,000)/3 = N90,000. Goodwill at 2 years purchase = N180,000. (2) Super profit method — Super profit = Actual profit - Normal profit. Goodwill = Super profit x Years\' purchase.', 'Financial Accounting'),
  tq('tfa19', 'X and Y are partners sharing profits 3:2. Z joins with 1/4 share, contributing N100,000 capital and N30,000 goodwill. Show journal entries for goodwill and prepare the new profit-sharing ratio.', 'Old ratio X:Y = 3:2 (60%:40%). Z gets 1/4 = 25%. Remaining 75% shared in old ratio. X = 75% x 3/5 = 45%, Y = 75% x 2/5 = 30%, Z = 25%. New ratio = 45:30:25 = 9:6:5. Goodwill: Dr Bank N30,000, Cr X Capital (30,000 x 3/5 = N18,000), Cr Y Capital (30,000 x 2/5 = N12,000). The incoming partner compensates existing partners for their share of goodwill.', 'Financial Accounting'),
  tq('tfa20', 'Explain the purpose and format of a balance sheet. From the following, prepare a balance sheet: Capital N500,000; Net profit N120,000; Drawings N40,000; Non-current assets (net) N350,000; Inventory N60,000; Debtors N45,000; Cash N35,000; Creditors N30,000; Loan N50,000.', 'Balance sheet: a snapshot of assets, liabilities, and equity at a point in time. Closing capital = 500,000 + 120,000 - 40,000 = N580,000. Balance Sheet: Non-current assets N350,000. Current assets: Inventory N60,000 + Debtors N45,000 + Cash N35,000 = N140,000. Total assets = N490,000. Capital N580,000. Non-current liabilities: Loan N50,000. Current liabilities: Creditors N30,000. Total equity + liabilities = 660,000. Missing assets of N170,000 (prepayments, investments, etc.) would balance the sheet.', 'Financial Accounting'),
  tq('tfa21', 'Explain the following accounting concepts: (a) Business entity concept (b) Money measurement concept (c) Prudence concept (d) Materiality concept.', '(a) Business entity: the business is separate from its owner(s). Personal transactions not recorded in business books. (b) Money measurement: only transactions measurable in monetary terms are recorded. (c) Prudence (conservatism): do not overstate assets/income or understate liabilities/expenses. (d) Materiality: only items significant enough to influence decisions need separate disclosure. Immaterial items can be treated practically.', 'Financial Accounting'),
  tq('tfa22', 'From the following, prepare a trading account for the year ended 31/12/2023: Opening stock N45,000; Purchases N320,000; Carriage inwards N15,000; Returns outwards N12,000; Closing stock N55,000; Sales N580,000; Returns inwards N20,000.', 'Net Sales = Sales - Returns inwards = 580,000 - 20,000 = N560,000. Cost of Sales = Opening stock N45,000 + Purchases N320,000 + Carriage inwards N15,000 - Returns outwards N12,000 - Closing stock N55,000 = N313,000. Gross Profit = 560,000 - 313,000 = N247,000. Trading Account: Cr: Sales N560,000. Dr: Opening stock N45,000, Purchases N320,000, Carriage N15,000, less Returns outwards N12,000, less Closing stock N55,000. GP c/d N247,000 transferred to P&L.', 'Financial Accounting'),
  tq('tfa23', 'Explain the purchase ledger control account (creditors control account) and prepare one from: Opening creditors N150,000; Credit purchases N680,000; Cash paid to creditors N520,000; Discount received N25,000; Returns outwards N35,000; Contra entry (transfer to sales ledger) N10,000; Closing creditors (balancing figure).', 'Purchase Ledger Control Account (total creditors): Dr: Cash paid N520,000 + Discount received N25,000 + Returns outwards N35,000 + Contra N10,000 = N590,000. Cr: Opening balance N150,000 + Credit purchases N680,000 = N830,000. Closing balance = 830,000 - 590,000 = N240,000. This equals total individual creditor balances. Control accounts summarise transactions and provide internal check on subsidiary ledgers.', 'Financial Accounting'),
  tq('tfa24', 'Explain the corrections of the following errors using journal entries: (a) Goods taken by proprietor N5,000 recorded as sales. (b) Rent paid N30,000 debited to rent account and credited to cash — but actually was for rates. (c) Purchase of machine N80,000 recorded in purchases account.', '(a) Goods taken by owner (drawings) wrongly treated as sale: Dr Sales N5,000, Cr Drawings N5,000. (b) If actually rates paid: Dr Rates N30,000, Cr Rent N30,000 (transfer). (c) Error of principle (capital expenditure as revenue): Dr Machinery N80,000, Cr Purchases N80,000. Each correcting entry restores proper double entry and correctly states the accounts.', 'Financial Accounting'),
  tq('tfa25', 'Explain the concept of a bill of exchange. A draws a bill on B for N100,000 at 3 months. B accepts the bill. Show the journal entries in A\'s and B\'s books.', 'Bill of exchange: an unconditional written order by the drawer (A) to the drawee (B) to pay a specified sum on a fixed date. In A\'s books: (1) When bill received: Dr Bills receivable N100,000, Cr B N100,000. (2) When matures: Dr Bank N100,000, Cr Bills receivable N100,000. (3) If discounted: Dr Bank (discounted amount), Dr Discount charges, Cr Bills receivable. In B\'s books: (1) When accepted: Dr A N100,000, Cr Bills payable N100,000. (2) When paid: Dr Bills payable N100,000, Cr Bank N100,000. If dishonoured: reverse with noting charges.', 'Financial Accounting'),
  tq('tfa26', 'Explain the different types of errors in accounting and classify them with examples.', 'Types: (1) Error of omission — transaction omitted entirely (e.g., credit sale not recorded). (2) Error of commission — correct amount, wrong account of same class (e.g., sale to A posted to B). (3) Error of principle — posted to wrong type of account (e.g., repairs posted to building asset). (4) Error of original entry — wrong amount (e.g., sale of N50,000 recorded as N5,000). (5) Compensating errors — two errors offset each other. (6) Complete reversal — debit posted as credit and vice versa. Correction: journal entries or suspense account adjustments.', 'Financial Accounting'),
  tq('tfa27', 'Calculate and interpret the following ratios: Net profit N150,000; Sales N1,200,000; Capital employed N800,000; Current assets N400,000; Current liabilities N200,000; Debtors N100,000; Credit sales N900,000. (a) Net profit margin (b) ROCE (c) Current ratio (d) Debtors collection period.', '(a) Net profit margin = 150,000/1,200,000 x 100 = 12.5%. (b) ROCE = 150,000/800,000 x 100 = 18.75%. (c) Current ratio = 400,000/200,000 = 2:1. (d) Debtors collection period = (100,000/900,000) x 365 = 40.6 days. Interpretation: 12.5% profit margin is reasonable; 18.75% ROCE shows good return; 2:1 current ratio shows adequate liquidity; 40.6 days collection is acceptable.', 'Financial Accounting'),
  tq('tfa28', 'What is a cash flow statement? Explain the difference between operating, investing, and financing activities with examples.', 'Cash flow statement: shows inflows and outflows of cash and cash equivalents classified into three activities. Operating activities: principal revenue-generating activities — cash from customers, payments to suppliers/employees. Investing activities: acquisition/disposal of long-term assets — purchase/sale of PPE, investments. Financing activities: changes in equity and borrowings — issue of shares, loans, dividends paid, loan repayment. The statement helps assess liquidity, solvency, and financial adaptability.', 'Financial Accounting'),
  tq('tfa29', 'Explain the procedure for preparing financial statements from a trial balance, including the sequence and interrelationships.', 'Sequence: (1) Trading account — calculates gross profit (Sales - Cost of Sales). (2) Profit and loss account — adds other income, deducts expenses from gross profit to get net profit. (3) Appropriation account (companies/partnerships) — allocates net profit to reserves, dividends, partners. (4) Balance sheet — lists assets, liabilities, and equity at period end. Interrelationships: Gross profit from trading account is first line in P&L. Net profit added to retained earnings in balance sheet. Closing stock from trading account is current asset in balance sheet.', 'Financial Accounting'),
  tq('tfa30', 'Explain the concept of stock valuation. A business has stock movements: 1/3 Opening 100 units @ N10 = N1,000; 5/3 Purchases 200 units @ N12 = N2,400; 10/3 Sales 150 units; 20/3 Purchases 300 units @ N15 = N4,500; 25/3 Sales 250 units. Calculate closing stock using FIFO and Weighted Average methods.', 'FIFO: Sales on 10/3: 100 @ N10 + 50 @ N12 = N1,600. Remaining: 150 @ N12 = N1,800. Sales on 25/3: 150 @ N12 + 100 @ N15 = N3,300. Closing stock: 200 @ N15 = N3,000. Weighted Average: After 5/3: 300 units, total N3,400, avg N11.33. Sale 150 units: COS = N1,699.50. After 20/3: 450 units, total N6,200, avg N13.78. Sale 250 units: COS = N3,444.44. Closing stock: 200 @ N13.78 = N2,755.56. FIFO gives higher closing stock.', 'Financial Accounting'),
  tq('tfa31', 'Explain the concept of Value Added Tax (VAT) and its accounting treatment. A company sells goods for N575,000 (VAT inclusive at 15% rate). Calculate the VAT amount and show the journal entries.', 'VAT: a consumption tax added to the selling price at each stage of production/distribution. Output VAT: VAT charged on sales. Input VAT: VAT paid on purchases. VAT payable = Output VAT - Input VAT. VAT inclusive price = N575,000. VAT = 15/115 x 575,000 = N75,000. Net sales = N500,000. Journal: Dr Debtors/Bank N575,000, Cr Sales N500,000, Cr VAT payable N75,000. On purchases: Dr Purchases, Dr VAT recoverable, Cr Creditors. VAT remitted periodically to tax authority. It is not a cost to the business.', 'Financial Accounting'),
  tq('tfa32', 'Explain the difference between partnerships and sole proprietorship. List four contents of a partnership deed.', 'Partnership: business owned by 2-20 partners sharing profits/losses. Sole proprietorship: one owner bearing all risks and taking all profits. Differences: Partners share capital/skills/risks; sole proprietor alone. Shared decision-making vs full control. Unlimited liability for both (unless LLP). Partnership dissolved by death/retirement. Deed contents: (1) Profit/loss sharing ratio. (2) Capital contributions. (3) Interest on capital/drawings. (4) Salaries/commission to partners. (5) Admission/retirement procedures. (6) Dissolution arrangements.', 'Financial Accounting'),
  tq('tfa33', 'A and B are partners sharing 3:2. Capitals: A N300,000, B N200,000. Interest on capital is 10% p.a. B is entitled to salary of N24,000 p.a. Net profit is N150,000. Show the appropriation account and partners\' current accounts.', 'Appropriation Account: Net profit N150,000. Less: Interest on capital: A (10% x 300,000 = N30,000) + B (10% x 200,000 = N20,000) = N50,000. Less: B\'s salary N24,000. Remaining profit = 150,000 - 50,000 - 24,000 = N76,000. Share: A (3/5 x 76,000 = N45,600), B (2/5 x 76,000 = N30,400). Current accounts: A: Interest N30,000 + Share N45,600 = N75,600 Cr. B: Salary N24,000 + Interest N20,000 + Share N30,400 = N74,400 Cr. Drawings would be debited.', 'Financial Accounting'),
  tq('tfa34', 'Explain the accounting treatment for depreciation and the disposal of non-current assets. A machine costing N200,000 (accumulated depreciation N80,000) is sold for N130,000. Show the journal entries.', 'Disposal entries: (1) Transfer cost: Dr Disposal N200,000, Cr Machine N200,000. (2) Transfer accumulated depreciation: Dr Accumulated depreciation N80,000, Cr Disposal N80,000. (3) Record sale: Dr Bank N130,000, Cr Disposal N130,000. (4) Calculate profit/loss: Disposal balance = Dr 200,000 - Cr 80,000 - Cr 130,000 = Dr 10,000 (loss). Dr P&L (loss on disposal) N10,000, Cr Disposal N10,000. Gain/loss = Proceeds - NBV = 130,000 - (200,000-80,000) = 10,000 loss.', 'Financial Accounting'),
  tq('tfa35', 'From the following, calculate: (i) Gross profit margin (ii) Mark-up percentage (iii) Rate of stock turnover. Opening stock N40,000; Purchases N280,000; Closing stock N60,000; Sales N450,000; Returns inwards N30,000.', 'Net Sales = 450,000 - 30,000 = N420,000. Cost of Sales = 40,000 + 280,000 - 60,000 = N260,000. Gross Profit = 420,000 - 260,000 = N160,000. (i) GP margin = 160,000/420,000 x 100 = 38.1%. (ii) Mark-up = 160,000/260,000 x 100 = 61.5%. (iii) Stock turnover = 260,000/[(40,000+60,000)/2] = 260,000/50,000 = 5.2 times. High turnover indicates efficient stock management.', 'Financial Accounting'),
  tq('tfa36', 'Explain the purpose and format of a department trading and profit and loss account. How are expenses apportioned among departments?', 'Departmental accounts: separate trading and P&L accounts for each department to measure performance. Format: separate columns showing sales, cost of sales, gross profit, expenses, net profit per department. Apportionment basis: Direct expenses traced directly. Indirect expenses: Rent/rates by floor area, Insurance by asset value, Lighting by floor area, Canteen by employee count, Admin salaries by turnover ratio. Inter-department transfers recorded at cost or selling price. Benefits: identifies profitable/unprofitable departments, aids decision-making.', 'Financial Accounting'),
  tq('tfa37', 'Explain the accounting treatment for subscriptions in a club (non-profit organisation). A club has 200 members paying N5,000 each annually. During 2023 received N980,000 including N20,000 arrears from 2022 and N30,000 advance for 2024. Calculate subscriptions income for 2023.', 'Subscriptions income = Amount relating to current year. Current year subscriptions = 200 x N5,000 = N1,000,000. Received for 2023 = 980,000 - 20,000 (2022 arrears) - 30,000 (2024 advance) = N930,000. Subscriptions in arrears at 31/12/2023 = 1,000,000 - 930,000 = N70,000 (current asset). Advance at 31/12/2023 = N30,000 (liability). Adjusting: Dr Subscriptions arrears N70,000, Cr Subscriptions income N70,000.', 'Financial Accounting'),
  tq('tfa38', 'Explain the concept of redemption of debentures. A company issued 10,000 10% debentures of N100 each. The debentures are redeemed at a premium of 5%. Show journal entries for redemption.', 'Debentures: long-term loans with fixed interest and security. Redemption: repaying debenture holders. Journal entries: (1) Dr Debentures N1,000,000, Dr Premium on redemption N50,000 (5% x 1,000,000), Cr Debenture holders N1,050,000. (2) Dr Debenture holders N1,050,000, Cr Bank N1,050,000. (3) Dr Profit & Loss (or Securities premium reserve) N50,000, Cr Premium on redemption N50,000. Premium on redemption is a capital loss charged to reserves or P&L.', 'Financial Accounting'),
  tq('tfa39', 'Explain the purpose of provisions and reserves. Distinguish between a provision for bad debts and a general reserve.', 'Provision: amount set aside for a known liability or expected loss (e.g., provision for doubtful debts, depreciation). Charged against profit (expense in P&L). Required by prudence concept. Reserve: appropriation of profit set aside for strengthening the business or future contingencies. Part of equity. Provision for bad debts: estimate of debts unlikely to be collected. Contra-asset deducted from debtors. General reserve: profit retained for general purposes (growth, expansion). Revenue reserves available for dividend; capital reserves (e.g., share premium) not distributable.', 'Financial Accounting'),
  tq('tfa40', 'From the following, prepare an income and expenditure account for a sports club: Subscriptions received N450,000; Salaries paid N120,000; Electricity paid N25,000; Purchase of equipment N60,000; Rent received N30,000; Donations received N50,000; Printing N15,000. Additional: Subscriptions in arrears N20,000; Subscriptions in advance N10,000; Salaries owed N8,000; Depreciation on equipment 10%.', 'Income: Subscriptions (450,000 + 20,000 arrears - 10,000 advance = N460,000) + Rent N30,000 + Donations N50,000 = N540,000. Expenditure: Salaries (120,000 + 8,000 owed = N128,000) + Electricity N25,000 + Printing N15,000 + Depreciation (10% x 60,000 = N6,000) = N174,000. Surplus = 540,000 - 174,000 = N366,000. Note: Purchase of equipment is capital expenditure — does not appear in income/expenditure account.', 'Financial Accounting'),
  tq('tfa41', 'Explain the difference between shares and debentures. A company issues 50,000 ordinary shares of N10 each at a premium of N2 per share. Show journal entries.', 'Shares: ownership/equity capital. Shareholders are owners, receive dividends, vote at AGM. Debentures: loan capital. Debenture holders are creditors, receive fixed interest, no voting rights. Journal for share issue: (1) Application: Dr Bank N600,000, Cr Share application N600,000. (2) Allotment: Dr Share application N600,000, Cr Share capital (50,000 x N10 = N500,000), Cr Share premium (50,000 x N2 = N100,000). Share premium is a capital reserve not available for dividends.', 'Financial Accounting'),
  tq('tfa42', 'Explain the straight-line method of depreciation. A delivery van costing N1,200,000 has estimated useful life of 5 years and scrap value of N200,000. Show the depreciation schedule for 3 years.', 'Straight-line: (Cost - Residual)/Life = (1,200,000 - 200,000)/5 = N200,000 per year. Year 1: Depreciation N200,000, Accumulated N200,000, NBV N1,000,000. Year 2: Depreciation N200,000, Accumulated N400,000, NBV N800,000. Year 3: Depreciation N200,000, Accumulated N600,000, NBV N600,000. Journal (each year): Dr Depreciation (P&L) N200,000, Cr Accumulated depreciation N200,000. At year 5, NBV = N200,000 = scrap value.', 'Financial Accounting'),
  tq('tfa43', 'What is a trial balance? The following trial balance totals do not agree: Debit N1,450,000; Credit N1,320,000. A suspense account is opened. In the next period, errors are discovered: (i) Sales of N50,000 omitted (ii) Rent paid N30,000 entered as N3,000. Show corrections.', 'Suspense account opening: Dr Suspense N130,000 (difference). (i) Error of omission: Dr Suspense N50,000, Cr Sales N50,000. (ii) Error: Rent understated by N27,000. Dr Rent N27,000, Cr Suspense N27,000. After corrections: Suspense = 130,000 - 50,000 + 27,000 = N107,000 Cr remaining. Further errors need to be found to clear the suspense account. The suspense account is temporary all errors must be found and corrected.', 'Financial Accounting'),
  tq('tfa44', 'Explain the reducing balance method of depreciation. An asset costing N500,000 is depreciated at 25% per annum reducing balance. Show the schedule for 4 years.', 'Reducing balance: depreciation charged on net book value each year. Year 1: 25% x 500,000 = N125,000, NBV N375,000. Year 2: 25% x 375,000 = N93,750, NBV N281,250. Year 3: 25% x 281,250 = N70,313, NBV N210,937. Year 4: 25% x 210,937 = N52,734, NBV N158,203. Journal each year: Dr Depreciation (P&L), Cr Accumulated depreciation. Higher depreciation in early years reflects higher efficiency. Higher maintenance costs in later years offset by lower depreciation.', 'Financial Accounting'),
  tq('tfa45', 'Explain the accounting treatment of research and development costs. How are they treated under IAS 38?', 'Under IAS 38: Research costs — expensed as incurred in P&L (no asset recognised because future benefits uncertain). Development costs — capitalised as intangible asset if criteria met: (1) Technical feasibility. (2) Intention to complete. (3) Ability to use/sell. (4) Future economic benefits. (5) Adequate resources. (6) Costs reliably measured. Capitalised development costs amortised over useful life. Journal: Research: Dr Research expense, Cr Cash. Development: Dr Development asset, Cr Cash. Amortisation: Dr Amortisation expense, Cr Accumulated amortisation.', 'Financial Accounting'),
  tq('tfa46', 'Prepare a simple profit and loss account from: Gross profit N500,000; Salaries N120,000; Rent N50,000; Advertising N30,000; Electricity N20,000; Insurance N15,000; Discount allowed N12,000; Discount received N8,000; Bad debts N10,000; Increase in provision for doubtful debts N5,000; Commission received N25,000; Loan interest N18,000; Depreciation N40,000.', 'P&L Account: Gross Profit b/d N500,000. Add other income: Discount received N8,000 + Commission N25,000 = N33,000. Total income = N533,000. Less expenses: Salaries N120,000 + Rent N50,000 + Advertising N30,000 + Electricity N20,000 + Insurance N15,000 + Discount allowed N12,000 + Bad debts N10,000 + Increase in provision N5,000 + Loan interest N18,000 + Depreciation N40,000 = N320,000. Net Profit = 533,000 - 320,000 = N213,000.', 'Financial Accounting'),
  tq('tfa47', 'Explain the concept of a receipts and payments account and how it differs from an income and expenditure account for non-profit organisations.', 'Receipts and Payments Account: summary of all cash receipts and payments during a period (like a cash book). Shows opening and closing cash/bank balances. Includes capital and revenue items. Cash basis. Does not show surplus/deficit. Income and Expenditure Account: like P&L for non-profits. Accrual basis. Shows income earned and expenses incurred. Shows surplus or deficit. Excludes capital receipts/payments. Adjusted for accruals, prepayments, depreciation, and provisions. A complete set of accounts includes both.', 'Financial Accounting'),
  tq('tfa48', 'From the following information, calculate the net profit using the single entry / net worth method: Capital at beginning of year N400,000; Capital at end of year N520,000; Drawings during year N80,000; Additional capital introduced N40,000.', 'Net profit = Closing capital - Opening capital - Additional capital + Drawings. = 520,000 - 400,000 - 40,000 + 80,000 = N160,000. Verification: Opening N400,000 + Capital N40,000 + Profit N160,000 - Drawings N80,000 = N520,000 = Closing capital. This method is used when full double entry records are not available. It gives overall profit but not detailed income/expense breakdown.', 'Financial Accounting'),
  tq('tfa49', 'Explain the process of issuing shares at par, premium, and discount. Show the journal entries for issuing 100,000 ordinary shares of N10 each at N12 per share.', 'At par: Dr Bank N1,000,000, Cr Share capital N1,000,000. At premium (N12): Dr Bank N1,200,000, Cr Share capital N1,000,000, Cr Share premium N200,000. At discount (rarely allowed): Dr Bank N800,000, Dr Discount on shares N200,000, Cr Share capital N1,000,000. Share premium is capital reserve for bonus shares, writing off preliminary expenses, or issuing premium on redemption. For premium: Application Dr Bank, Cr Share application. Allotment Dr Share application, Cr Share capital, Cr Share premium.', 'Financial Accounting'),
  tq('tfa50', 'Explain the meaning and purpose of consolidated financial statements. Which entities are required to prepare consolidated accounts?', 'Consolidated financial statements: combined financial statements of a parent company and its subsidiaries, presented as a single economic entity. Purpose: shows overall financial position, performance, and cash flows. Required when parent controls subsidiaries (>50% ownership). Consolidation adjustments: eliminate cost of investment against subsidiary equity, eliminate inter-company transactions, record non-controlling interest. Standards: IFRS 10. Group accounts include: consolidated balance sheet, income statement, cash flow statement, and notes.', 'Financial Accounting'),
  tq('tfa51', 'Explain the difference between a fixed asset and a current asset. Give three examples of each.', 'Fixed (non-current) assets: held for long-term use (>1 year) to generate revenue. Not held for resale. Examples: land and buildings, plant and machinery, motor vehicles, furniture, patents. Current assets: held for short-term conversion to cash within one year. Examples: inventory (stock), trade debtors, cash and bank balances, prepayments, short-term investments. Distinction affects liquidity analysis (current ratio) and balance sheet classification.', 'Financial Accounting'),
  tq('tfa52', 'What is a statement of affairs? Explain how it is prepared in an incomplete records situation.', 'Statement of affairs: a statement of assets and liabilities at a date, prepared under single entry/incomplete records. It is essentially a balance sheet from available information. Purpose: determines capital to compute profit. Structure: lists all assets and liabilities. Capital = Total assets - Total liabilities (balancing figure). Two statements: opening (start capital) and closing (end capital). Profit = Closing capital - Opening capital + Drawings - Additional capital. Limitations: less reliable than double entry, may miss items, no detailed breakdown.', 'Financial Accounting'),
  tq('tfa53', 'Explain the accounting concept of materiality and how it affects financial reporting decisions.', 'Materiality: an item is material if its omission or misstatement could influence economic decisions of users. It is a threshold. Application: (1) Small expenses (e.g., N500 stapler) can be treated as expense. (2) Immaterial errors may not need correction. (3) Items below threshold may be aggregated. Assessment depends on size and nature relative to financial statements. Benchmarks: 0.5%-5% of net profit or total assets. Professional judgment required. IFRS requires disclosure of material items.', 'Financial Accounting'),
  tq('tfa54', 'Explain the accounting treatment for hire purchase transactions from the buyer\'s perspective.', 'Hire purchase: buyer acquires asset by paying instalments, gaining ownership after final payment. Asset and liability recorded at cash price (fair value) at inception. Journal: Dr Asset (cash price), Cr HP creditor. Each instalment: part interest, part capital repayment. Dr HP creditor (capital portion), Dr Interest expense (P&L), Cr Bank. Depreciation charged on asset cost over useful life. HP creditor: current portion (due within 1 year) and non-current portion (due after 1 year). Total interest = HP price - Cash price.', 'Financial Accounting'),
  tq('tfa55', 'From the following, calculate the acid test (quick) ratio and comment on liquidity: Current assets: inventory N80,000, debtors N60,000, prepayments N10,000, cash N20,000. Current liabilities: creditors N70,000, accruals N15,000, bank overdraft N25,000.', 'Acid test (quick) ratio = (Current assets - Inventory - Prepayments) / Current liabilities. Quick assets = Debtors N60,000 + Cash N20,000 = N80,000. Current liabilities = 70,000 + 15,000 + 25,000 = N110,000. Quick ratio = 80,000/110,000 = 0.73:1. A ratio of 1:1 is satisfactory. 0.73:1 means potential liquidity problem. Current ratio = 170,000/110,000 = 1.55:1. Advice: reduce overdraft, collect debtors faster, negotiate longer credit terms.', 'Financial Accounting'),
  tq('tfa56', 'Explain the accounting treatment for government grants under IAS 20. A company receives a government grant of N500,000 towards purchase of machinery costing N2,000,000.', 'Under IAS 20, two approaches: (1) Capital approach — grant credited to deferred income (liability) and amortised to income over asset\'s useful life. Dr Bank N500,000, Cr Deferred income N500,000. Each year: Dr Deferred income, Cr Other income. (2) Deduction approach — grant deducted from carrying amount. Dr Bank N500,000, Cr Machinery N500,000. Depreciation on net cost of N1,500,000. The capital approach (deferred income) is more common and transparent.', 'Financial Accounting'),
  tq('tfa57', 'Explain the term contingent liability and its accounting treatment under IAS 37. Give two examples.', 'Contingent liability under IAS 37: (1) Possible obligation from past events confirmed by uncertain future events. OR (2) Present obligation not recognised because outflow not probable or amount not measurable. Treatment: NOT recognised in financial statements. DISCLOSED in notes unless outflow remote. Examples: (1) Lawsuit against the company with uncertain outcome. (2) Guarantee given for another entity\'s loan. If obligation becomes probable and measurable, it becomes a provision (recognised as liability). Contingent assets: possible asset not recognised, disclosed if inflow is probable.', 'Financial Accounting'),
  tq('tfa58', 'From the following, prepare a bank reconciliation statement: Balance as per cash book N85,000; Balance as per bank statement N110,000; Uncredited cheques N30,000; Unpresented cheques N20,000; Bank charges not in cash book N8,000; Direct deposit from customer not in cash book N15,000.', 'Step 1: Adjusted cash book. Start N85,000. Less: Bank charges N8,000 = N77,000. Add: Direct deposit N15,000 = N92,000. Adjusted cash book = N92,000. Step 2: Bank reconciliation. Balance per bank statement N110,000. Less: Uncredited cheques N30,000 = N80,000. Add: Unpresented cheques N20,000 = N100,000. Adjusted bank = N100,000. Difference of N8,000 needs further investigation (possibly another error or item). Bank reconciliation is a crucial internal control.', 'Financial Accounting'),
  tq('tfa59', 'Explain the characteristics of company financial statements under IFRS. What are the components of a complete set of financial statements?', 'Under IAS 1, a complete set includes: (1) Statement of Financial Position. (2) Statement of Profit or Loss and Other Comprehensive Income. (3) Statement of Changes in Equity. (4) Statement of Cash Flows. (5) Notes (accounting policies, disclosures). Characteristics: fair presentation, going concern, accrual basis, consistency, materiality, aggregation, no offsetting (unless required), comparative information, at least annually. IFRS is principles-based. Financial statements must give a true and fair view.', 'Financial Accounting'),
  tq('tfa60', 'Explain the different types of shares that a company can issue. Distinguish between ordinary shares and preference shares.', 'Types: (1) Ordinary (equity) shares — ownership, voting rights, dividends at discretion, residual claim on assets. Highest risk and return. (2) Preference shares — fixed dividend rate, priority over ordinary for dividends and liquidation. Usually no voting rights. Types: Cumulative/Non-cumulative, Participating, Redeemable, Convertible. Preference shares are hybrid — fixed return but ranked after debt on liquidation. Companies may issue at par, premium, or (in some cases) discount.', 'Financial Accounting'),
  tq('tfa61', 'A company purchases a machine on 1/1/2022 for N800,000. Depreciation is 20% per annum reducing balance. Prepare the machine account and accumulated depreciation account for 3 years.', 'Year 2022: Depreciation = 20% x 800,000 = N160,000. NBV = N640,000. Year 2023: Depreciation = 20% x 640,000 = N128,000. NBV = N512,000. Year 2024: Depreciation = 20% x 512,000 = N102,400. NBV = N409,600. Machine account: Dr 1/1/22 Bank/Supplier N800,000. Balance c/d N800,000 each year. Accumulated depreciation: Yr 1: Dr P&L N160,000, Cr Acc depr N160,000. Yr 2: Dr P&L N128,000, Cr Acc depr N128,000 (bal N288,000). Yr 3: Dr P&L N102,400, Cr Acc depr N102,400 (bal N390,400). NBV in balance sheet = Cost less accumulated depreciation.', 'Financial Accounting'),
  tq('tfa62', 'Explain the concept of internal controls in accounting and give four examples of internal control procedures.', 'Internal controls: policies and procedures to safeguard assets, ensure accuracy of records, promote operational efficiency, and ensure compliance with laws. Examples: (1) Segregation of duties — different people handle authorisation, custody, and recording. (2) Authorisation — transactions approved by appropriate personnel. (3) Physical controls — locks, secure storage, CCTV for assets. (4) Bank reconciliation — regular comparison of cash book and bank statement. (5) Control accounts — agree subsidiary ledgers with control accounts. (6) Audit trail — documentation for verification. Good internal controls reduce error and fraud risk.', 'Financial Accounting'),
  tq('tfa63', 'Explain the accounting treatment for dividends. A company declares a dividend of N2 per share on 500,000 ordinary shares. Show the journal entries for declaration and payment.', 'Dividend: distribution of profits to shareholders. Declaration: Dr Retained earnings (or Appropriation account) N1,000,000, Cr Dividends payable N1,000,000. Payment: Dr Dividends payable N1,000,000, Cr Bank N1,000,000. Dividend is not an expense — it is an appropriation of profit. It does not appear in P&L. Shown in Appropriation account or Statement of Changes in Equity. Interim dividend: paid during the year. Final dividend: proposed after year-end, disclosed as note if not yet declared.', 'Financial Accounting'),
  tq('tfa64', 'Explain the purpose and preparation of a partnership dissolution account. A and B dissolve partnership. Assets realised N600,000; Liabilities paid N150,000; Realisation expenses N20,000. Partners share profits equally. Show the realisation account.', 'Dissolution: winding up of partnership. Realisation account: records sale of assets and payment of liabilities. Dr: Assets transferred at book value, Realisation expenses. Cr: Assets sold at realised value, Creditors paid. Balance: profit or loss on realisation transferred to partners\' capital accounts in profit-sharing ratio. Realisation A/c: Cr Assets realised N600,000, Dr Liabilities paid N150,000, Dr Expenses N20,000. Net profit on realisation = 600,000 - 150,000 - 20,000 = N430,000. Shared equally: A N215,000, B N215,000.', 'Financial Accounting'),
  tq('tfa65', 'From the following, calculate the gross profit and net profit: Sales N950,000; Sales returns N50,000; Opening stock N80,000; Purchases N620,000; Purchases returns N20,000; Carriage inwards N15,000; Carriage outwards N25,000; Closing stock N100,000; Operating expenses N120,000; Discount received N10,000; Rent income N30,000.', 'Net Sales = 950,000 - 50,000 = N900,000. Cost of Sales = 80,000 + 620,000 - 20,000 + 15,000 - 100,000 = N595,000. Gross Profit = 900,000 - 595,000 = N305,000. Net Profit = GP N305,000 + Discount received N10,000 + Rent income N30,000 - Carriage outwards N25,000 - Operating expenses N120,000 = N200,000. Carriage inwards is part of cost of sales; carriage outwards is selling expense in P&L.', 'Financial Accounting'),
  tq('tfa66', 'Explain the concept of segment reporting under IFRS 8. Why is segment information useful to investors?', 'IFRS 8: operating segments are components of an entity that engage in business activities whose results are reviewed by the chief operating decision maker and for which discrete financial information is available. Disclosure: segment revenue, profit/loss, assets, liabilities, and other items for each reportable segment. Usefulness: helps investors understand the entity\'s different business activities and economic environments in which it operates. Enables better assessment of risks, opportunities, and performance of diverse operations. Most entities report by business or geographic segments.', 'Financial Accounting'),
  tq('tfa67', 'Explain the straight-line and reducing balance methods of providing for depreciation. Why might a company choose one method over the other?', 'Straight-line: equal annual charge (Cost - Residual)/Life. Advantages: simple, predictable. Used when asset provides equal benefits each year (e.g., buildings, fixtures). Reducing balance: higher charge in early years. Advantages: matches depreciation to efficiency pattern (more benefit in early years), tax advantage (higher early deductions), offsets rising maintenance costs. Used for assets with high initial productivity (vehicles, technology). Choice based on pattern of economic benefits consumption. Once chosen, consistency concept requires same method unless circumstances change. Both must be disclosed as accounting policy.', 'Financial Accounting'),
  tq('tfa68', 'Explain the accounting treatment for inventory valuation under IAS 2. What costs are included in inventory?', 'Under IAS 2: inventory measured at lower of cost and net realisable value (NRV). Cost includes: purchase cost, import duties, transport, handling, and other directly attributable costs less discounts. Production costs: direct materials, direct labour, and allocated production overheads (fixed and variable). Cost formulas: FIFO or weighted average cost (specific identification for unique items). LIFO is prohibited under IFRS. NRV = estimated selling price less estimated completion and selling costs. Write-down to NRV recognised as expense. Reversal of write-down allowed if NRV recovers.', 'Financial Accounting'),
  tq('tfa69', 'A company has the following balances: Issued share capital N2,000,000; Share premium N500,000; Retained earnings N800,000; Non-current assets N2,400,000; Current assets N1,600,000; 10% Loan N600,000; Current liabilities N400,000. Prepare the statement of financial position (balance sheet) in a vertical format.', 'Statement of Financial Position: Non-current assets N2,400,000. Current assets N1,600,000. Total assets N4,000,000. Equity: Share capital N2,000,000 + Share premium N500,000 + Retained earnings N800,000 = N3,300,000. Non-current liabilities: 10% Loan N600,000. Current liabilities N400,000. Total equity and liabilities = 3,300,000 + 600,000 + 400,000 = N4,300,000. Note: difference of N300,000 needs reconciliation — careful check of actual figures needed. The balance sheet must balance (A = E + L). Missing items or misclassification possible.', 'Financial Accounting'),
  tq('tfa70', 'Explain the concept of substance over form in accounting. Give an example of its application.', 'Substance over form: transactions should be accounted for based on their economic reality (substance) rather than their legal form. Required by IAS 1 framework. Example: Finance leases. Legally, the lessor owns the asset. But if the lessee bears the risks and rewards of ownership (substance), the lessee records the asset and liability (finance lease), even though legal title remains with the lessor. Other examples: Sale and leaseback arrangements, consignment inventory (may not be sale despite transfer), consolidated accounts (group as single entity despite separate legal entities).', 'Financial Accounting'),
  tq('tfa71', 'Explain the accounting treatment for prior period errors under IAS 8. A company discovered that depreciation of N50,000 was omitted in the previous year. Show the correction.', 'Under IAS 8, prior period errors are corrected retrospectively by restating comparative amounts. If error is material: Dr Retained earnings (opening) N50,000, Cr Accumulated depreciation N50,000. The correction adjusts the opening balance of retained earnings, not current year P&L. Disclosure: nature of error, amount of correction for each prior period presented, amount of correction at beginning of earliest period presented. Immaterial errors corrected in current period. Unlike changes in estimates (prospective), errors require retrospective restatement.', 'Financial Accounting'),
  tq('tfa72', 'Explain the purpose of the profit and loss appropriation account for partnerships and companies. Show the format for a partnership.', 'Appropriation account shows how net profit is allocated. For partnerships: Net profit b/d from P&L. Less: Interest on capital (partners), Salaries to partners. Remaining profit shared in profit-sharing ratio. Add: Interest on drawings (deducted from partners). Format: Net Profit X. Add Interest on drawings X. Less Interest on capital (X), Salaries (X). Residual profit shared: Partner A (ratio) X, Partner B (ratio) X. For companies: Net profit, less Transfer to reserves, Proposed dividends, Retained earnings carried forward. The balance is added to retained earnings in balance sheet.', 'Financial Accounting'),
  tq('tfa73', 'Explain the purpose and contents of the statement of changes in equity under IFRS.', 'Statement of Changes in Equity: reconciles opening and closing equity balances. Shows all changes in equity (not just transactions with owners). Contents for each component (share capital, share premium, retained earnings, revaluation reserve, etc.): (1) Opening balance. (2) Comprehensive income for the period (profit/loss, OCI items). (3) Transactions with owners (dividends, share issues, share buybacks). (4) Other changes (transfers between reserves). (5) Closing balance. Required by IAS 1. Provides a complete picture of how equity changed, including owner contributions/distributions and total comprehensive income.', 'Financial Accounting'),
  tq('tfa74', 'Explain the calculation of earnings per share (EPS). A company has net profit of N600,000 and has 1,000,000 ordinary shares in issue throughout the year. Calculate the EPS.', 'Basic EPS = Profit attributable to ordinary shareholders / Weighted average number of ordinary shares outstanding. EPS = 600,000 / 1,000,000 = N0.60 per share (or 60 kobo per share). If preference shares existed: Profit attributable = Net profit - Preference dividends. Diluted EPS: adjusts for potential ordinary shares (share options, convertible bonds/debentures, convertible preference shares). Diluted EPS shows maximum potential dilution. EPS is a key performance indicator used by investors. Required disclosure under IAS 33 for listed companies.', 'Financial Accounting'),
  tq('tfa75', 'Explain the difference between a fixed budget and a flexible budget. Why is a flexible budget more useful for control purposes?', 'Fixed budget: prepared for a single level of activity. Does not change when actual activity differs. Useful for planning but poor for control if activity varies. Flexible budget: shows expected costs and revenues at different activity levels. Separates fixed and variable costs. For control: actual results compared with flexible budget at actual activity level. Variances show efficiency (not just volume effects). Example: If actual production is 9,000 units but budget was 10,000, the flexible budget recasts at 9,000 units. Variance = Actual vs Flexible budget (not fixed budget). Better performance evaluation.', 'Financial Accounting'),
  tq('tfa76', 'Explain the accounting treatment for loan notes (debentures) including issue, interest, and redemption. Show entries for issuing N500,000 8% debentures at par.', 'Issue: Dr Bank N500,000, Cr Debentures N500,000. Annual interest: Dr Finance cost (P&L) N40,000 (8% x 500,000), Cr Bank N40,000. Issue at discount: Dr Bank (net), Dr Discount on debentures, Cr Debentures. Discount amortised to P&L over life. Issue at premium: Dr Bank, Cr Debentures, Cr Premium on debentures. Redemption: Dr Debentures, Cr Bank. Premium on redemption: Dr P&L/Reserves, Cr Bank. Debentures are non-current liabilities. Interest is a finance cost (not appropriation like dividends). Debenture holders are creditors, not owners.', 'Financial Accounting'),
  tq('tfa77', 'From the following, prepare a trial balance as at 31/12/2023: Capital N400,000; Drawings N30,000; Sales N700,000; Purchases N450,000; Opening stock N50,000; Salaries N80,000; Rent N40,000; Electricity N15,000; Debtors N95,000; Creditors N60,000; Cash N25,000; Bank N70,000; Equipment N250,000; Loan N100,000; Commission received N20,000; Discount allowed N10,000; Discount received N15,000; Returns inwards N12,000; Returns outwards N8,000; Carriage inwards N5,000; Carriage outwards N7,000. (Balancing figure.)', 'List all debit balances: Drawings 30,000 + Purchases 450,000 + Opening stock 50,000 + Salaries 80,000 + Rent 40,000 + Electricity 15,000 + Debtors 95,000 + Cash 25,000 + Bank 70,000 + Equipment 250,000 + Discount allowed 10,000 + Returns inwards 12,000 + Carriage inwards 5,000 + Carriage outwards 7,000 = Total debits N1,139,000. Credit balances: Capital 400,000 + Sales 700,000 + Creditors 60,000 + Loan 100,000 + Commission received 20,000 + Discount received 15,000 + Returns outwards 8,000 = Total credits N1,303,000. Difference (balancing) = N164,000. Verify: likely closing stock adjustment, or suspense needed. Trial balance totals: Dr N1,139,000; Cr N1,303,000. Difference N164,000.', 'Financial Accounting'),
  tq('tfa78', 'Explain the concept of fair value measurement under IFRS 13. Give examples of where fair value is used in financial reporting.', 'IFRS 13 defines fair value as the price that would be received to sell an asset or paid to transfer a liability in an orderly transaction between market participants at the measurement date. Fair value hierarchy (3 levels): Level 1 — quoted prices in active markets (most reliable). Level 2 — observable inputs (similar assets, interest rates). Level 3 — unobservable inputs (entity\'s own data, least reliable). Used in: investment property (IAS 40), financial instruments (IFRS 9), business combinations (IFRS 3), biological assets (IAS 41), impairment testing (IAS 36). Fair value provides more relevant but potentially less reliable information than historical cost.', 'Financial Accounting'),
  tq('tfa79', 'A company has current assets of N500,000 and current liabilities of N250,000. It plans to purchase inventory for N50,000 on credit. Show the effect on the current ratio before and after the purchase.', 'Before purchase: Current ratio = 500,000/250,000 = 2:1. After purchase on credit: Current assets increase by N50,000 (inventory) = N550,000. Current liabilities increase by N50,000 (creditors) = N300,000. New current ratio = 550,000/300,000 = 1.83:1. The current ratio decreases from 2:1 to 1.83:1. This illustrates that purchasing on credit worsens the current ratio (even though the company is acquiring assets). The quick ratio would decrease even more because inventory (non-quick) increases while quick assets remain unchanged.', 'Financial Accounting'),
  tq('tfa80', 'Explain the accounting treatment for revaluation of non-current assets under IAS 16. A building cost N1,000,000 (accumulated depreciation N200,000) is revalued to N1,200,000. Show the journal entries.', 'Under IAS 16, revaluation model: assets carried at revalued amount (fair value less subsequent depreciation). Net carrying amount method: Dr Building N200,000 (gross increase), Dr Accumulated depreciation N200,000, Cr Revaluation reserve N400,000. (NBV increases from 800,000 to 1,200,000). Gross method: Dr Building N400,000 (gross up to new cost), Dr Accumulated depreciation N200,000 (eliminated), Cr Revaluation reserve N400,000. Subsequent depreciation based on new revalued amount. Revaluation reserve: part of OCI, transferred to retained earnings on asset disposal or over asset life (excess depreciation). Revaluation losses: expense in P&L (or reduce revaluation reserve if available).', 'Financial Accounting'),
  tq('tfa81', 'Explain the accounting treatment of finance leases from the lessee\'s perspective under IFRS 16.', 'Under IFRS 16, lessees recognise a right-of-use (ROU) asset and lease liability for all leases (except short-term or low-value). Initial recognition: Dr Right-of-use asset, Cr Lease liability (at present value of lease payments). Include: fixed payments, variable payments depending on index/rate, residual value guarantees, purchase options (if reasonably certain). Subsequent: Depreciate ROU asset over useful life or lease term. Interest on lease liability using effective interest method. Dr Depreciation (P&L), Dr Finance cost (P&L), Cr ROU asset, Cr Lease liability (Repayment). This eliminates the previous classification of operating vs finance leases for lessees, bringing most leases onto the balance sheet.', 'Financial Accounting'),
  tq('tfa82', 'Explain the concept of impairment of assets under IAS 36. A machine has carrying amount N300,000 and recoverable amount N220,000. Show the journal entries.', 'IAS 36: assets should not be carried at more than recoverable amount (higher of fair value less costs to sell and value in use). Impairment loss = Carrying amount - Recoverable amount = 300,000 - 220,000 = N80,000. Journal: Dr Impairment loss (P&L) N80,000, Cr Accumulated impairment (or directly reduce asset) N80,000. After impairment: new carrying amount N220,000. Depreciation based on new amount. Indicators of impairment: external (market decline, technology change, interest rate increases) and internal (obsolescence, physical damage, restructuring). Reversal of impairment allowed for certain assets (not goodwill) if recoverable amount recovers.', 'Financial Accounting'),
  tq('tfa83', 'Explain the calculation and interpretation of the following ratios: (i) Gross profit margin (ii) Net profit margin (iii) Return on capital employed (ROCE) (iv) Current ratio.', '(i) Gross profit margin = (GP/Sales) x 100. Measures profitability of sales after direct costs. Higher = better. (ii) Net profit margin = (Net profit/Sales) x 100. Measures overall profitability after all expenses. (iii) ROCE = (Net profit/Capital employed) x 100. Measures efficiency of using capital. Should exceed cost of borrowing. (iv) Current ratio = Current assets/Current liabilities. Measures short-term liquidity. Ideal: 2:1. Too high = idle resources; too low = liquidity risk. These ratios help assess profitability, efficiency, and liquidity. Compare with industry averages and trends over time.', 'Financial Accounting'),
  tq('tfa84', 'Explain the accounting treatment for deferred tax under IAS 12. Give an example of a temporary difference.', 'Deferred tax: amounts of tax payable/recoverable in future periods arising from temporary differences between carrying amount and tax base of assets/liabilities. Temporary differences: e.g., depreciation method (straight-line for accounts, reducing balance for tax). Year 1: Accounts depreciation N100,000, Tax depreciation N150,000. Taxable profit < Accounting profit. Deferred tax liability (future tax payable) = Tax rate x temporary difference. Journal: Dr Tax expense (P&L), Cr Deferred tax liability. When temporary difference reverses: Dr Deferred tax liability, Cr Tax expense. Deferred tax assets recognised for deductible temporary differences (subject to recoverability assessment).', 'Financial Accounting'),
  tq('tfa85', 'Explain the purpose of a receipts and payments account. From the following, prepare a receipts and payments account for a club: Opening cash N25,000; Subscriptions received N180,000; Donations N40,000; Rent paid N30,000; Electricity N12,000; Salaries N50,000; Equipment purchased N45,000; Stationery N8,000; Closing cash (balancing figure).', 'Receipts and Payments Account for year ended...: Receipts: Opening cash b/d N25,000 + Subscriptions N180,000 + Donations N40,000 = N245,000. Payments: Rent N30,000 + Electricity N12,000 + Salaries N50,000 + Equipment N45,000 + Stationery N8,000 = N145,000. Closing cash (balancing) = 245,000 - 145,000 = N100,000. The account simply records cash receipts and payments — it does not distinguish capital/revenue or apply accruals. It shows opening and closing cash balances. Differences from income/expenditure account: includes capital items, excludes accruals/prepayments.', 'Financial Accounting'),
  tq('tfa86', 'Explain the concept of a change in accounting estimate. Give an example and show the accounting treatment under IAS 8.', 'Change in accounting estimate: adjustment of carrying amount of an asset/liability from reassessment of expected future benefits/obligations (e.g., useful life, residual value, bad debt provision). Treated prospectively (current and future periods, not retrospectively). Example: Asset cost N500,000, originally estimated life 10 years, depreciation N50,000/year. After 3 years, remaining useful life revised to 5 years (total 8). Carrying amount at revision = 500,000 - 150,000 = N350,000. New depreciation = 350,000/5 = N70,000/year for remaining 5 years. No adjustment to prior years. Disclose nature and amount of change if material.', 'Financial Accounting'),
  tq('tfa87', 'Explain the accounting treatment for events after the reporting period under IAS 10. Distinguish between adjusting and non-adjusting events.', 'IAS 10: events after the reporting period occur between the balance sheet date and the date financial statements are authorised for issue. Adjusting events: provide evidence of conditions existing at balance sheet date. Adjust financial statements. Examples: bankruptcy of debtor (confirming year-end provision), settlement of court case, sale of inventory at below cost. Non-adjusting events: indicative of conditions arising after balance sheet date. Do not adjust — DISCLOSE in notes if material. Examples: major business combination, fire/flood damage after year-end, significant share issue, changes in exchange rates.', 'Financial Accounting'),
  tq('tfa88', 'From the following, prepare the profit and loss account of a sole trader for the year ended 31/12/2023: Gross profit N340,000; Salaries N80,000; Rent N35,000; Insurance N12,000; Advertising N18,000; Discount allowed N7,000; Discount received N5,000; Commission received N15,000; Bad debts N9,000; Depreciation N22,000; General expenses N25,000; Loan interest N10,000.', 'P&L Account: Gross profit b/d N340,000. Add other income: Discount received N5,000 + Commission received N15,000 = N20,000. Total income = N360,000. Less expenses: Salaries N80,000 + Rent N35,000 + Insurance N12,000 + Advertising N18,000 + Discount allowed N7,000 + Bad debts N9,000 + Depreciation N22,000 + General expenses N25,000 + Loan interest N10,000 = N218,000. Net profit = 360,000 - 218,000 = N142,000. Net profit transferred to capital account (added to opening capital less drawings).', 'Financial Accounting'),
  tq('tfa89', 'Explain the difference between basic EPS and diluted EPS under IAS 33. Why is diluted EPS important?', 'Basic EPS = Profit attributable to ordinary shareholders / Weighted average shares outstanding. Uses actual shares. Diluted EPS: shows what EPS would be if all dilutive potential ordinary shares were converted (share options, warrants, convertible bonds/preference shares). Calculated: Adjusted profit / (Weighted avg shares + Dilutive potential shares). Diluted EPS is important because: (1) Shows maximum potential dilution of earnings. (2) More conservative measure (prudence). (3) Helps investors assess the impact of equity instruments on future earnings per share. (4) Required disclosure for listed companies. Always equal to or less than basic EPS.', 'Financial Accounting'),
  tq('tfa90', 'Explain the concept of a related party transaction under IAS 24. Give three examples and state the disclosure requirements.', 'Related party: a person/entity that controls, is controlled by, or has significant influence over the reporting entity (e.g., parent, subsidiary, key management, close family members). Related party transaction: transfer of resources/services between related parties regardless of price. Examples: (1) Sale of goods by parent to subsidiary. (2) Loan to director. (3) Management fees paid to parent company. Disclosure: nature of relationship, description of transactions, amounts involved, outstanding balances, provisions for doubtful debts, amounts written off. Required to ensure financial statements reflect potential conflicts of interest.', 'Financial Accounting'),
  tq('tfa91', 'Explain the concept of cost accounting and distinguish between fixed costs and variable costs. Give two examples of each.', 'Cost accounting: the process of recording, classifying, summarising, and allocating costs to determine product costs and aid management decisions. Fixed costs: remain constant in total regardless of activity level (within relevant range). Per unit: decrease as activity increases. Examples: rent, salaries, insurance, depreciation (straight-line). Variable costs: change in direct proportion to activity level. Per unit: remain constant. Examples: direct materials, direct labour (piece-rate), sales commission. Semi-variable costs: both fixed and variable components (e.g., electricity with standing charge + usage charge). Understanding cost behaviour is essential for break-even analysis, budgeting, and decision-making.', 'Financial Accounting'),
  tq('tfa92', 'Explain the accounting treatment for provisions under IAS 37. A company has a legal obligation to decommission a plant at estimated cost of N500,000 in 5 years. Show the entries using a discount rate of 10%.', 'IAS 37: a provision is a liability of uncertain timing or amount. Recognised when: (1) Present obligation from past event. (2) Probable outflow of resources. (3) Reliable estimate possible. Measured at best estimate (present value if time value material). Provision = 500,000/(1.10)^5 = N310,461. Journal: Dr Non-current asset (decommissioning cost) N310,461, Cr Provision N310,461. Each year: unwinding of discount — Dr Finance cost, Cr Provision (increase). Year 1: 310,461 x 10% = N31,046. Provision after year 1: N341,507. At year 5: provision = N500,000. Depreciation of asset over useful life.', 'Financial Accounting'),
  tq('tfa93', 'Explain the purpose of the statement of cash flows and describe the direct and indirect methods for presenting operating cash flows.', 'Statement of cash flows: shows cash inflows/outflows classified into operating, investing, and financing activities. Purpose: assesses liquidity, solvency, financial adaptability, and quality of earnings. Direct method: shows major classes of operating cash receipts and payments (receipts from customers, payments to suppliers/employees). Preferred by IAS 7 (encouraged) but less common in practice. Indirect method: starts with profit/loss, adjusts for non-cash items (depreciation, provisions), changes in working capital, and non-operating items. Most commonly used. Both methods give same net cash from operating activities. Must also show investing and financing activities.', 'Financial Accounting'),
  tq('tfa94', 'Explain the concept of segmental analysis and how it is used to evaluate business performance.', 'Segmental analysis: breaking down business performance by segments (products, services, geographic areas, customer types). Purpose: identify profitable/unprofitable segments, allocate resources effectively, support strategic decisions. Process: calculate revenue, cost, and profit for each segment. Contribution margin = Segment revenue - Variable costs. Segment profit = Contribution margin - Direct fixed costs. Common costs (shared overheads) allocated on reasonable basis or not allocated. Ratios: segment margin, segment ROA, growth rate. Example: a company may find its electronics segment is more profitable than clothing. Decision: invest more in electronics, fix or divest clothing.', 'Financial Accounting'),
  tq('tfa95', 'Explain the differences between management accounting and financial accounting.', 'Management accounting: internal focus, provides information to managers for planning, control, and decision-making. No mandatory format, future-oriented, detailed, frequent. Uses cost-volume-profit analysis, budgeting, variance analysis, relevant costing. Financial accounting: external focus, provides information to investors, creditors, regulators. Mandatory format (IFRS/GAAP), historical, summarised, annual/quarterly. Focus on reliability, comparability. Differences: Management (internal users, future, segments, no legal requirement) vs Financial (external users, past, entity-wide, legally required). Both systems draw from the same underlying transaction data but serve different purposes.', 'Financial Accounting'),
  tq('tfa96', 'Explain the concept of variance analysis in standard costing. A company budgeted for 1,000 units at N50 each (material cost). Actual: 1,100 units used 5,500 kg at N48 per kg. Standard: 5 kg per unit at N50 per kg. Calculate the material price and usage variances.', 'Standard cost per unit: 5 kg x N50 = N250. Actual cost: 5,500 kg x N48 = N264,000. Standard cost for actual production: 1,100 units x 5 kg = 5,500 kg (standard) x N50 = N275,000. Material price variance = (Standard price - Actual price) x Actual quantity = (50-48) x 5,500 = N11,000 Favourable. Material usage variance = (Standard quantity - Actual quantity) x Standard price = (5,500-5,500) x 50 = N0 (no variance — quantity matches). Total material variance = 275,000 - 264,000 = N11,000 Favourable. Favourable means actual cost less than standard (good). Analysis helps identify problem areas and take corrective action.', 'Financial Accounting'),
  tq('tfa97', 'Explain the accounting treatment for business combinations (acquisitions) under IFRS 3. Company A acquires Company B for N800,000. Net identifiable assets of B are valued at N700,000. Show the entries.', 'Under IFRS 3 (acquisition method): (1) Identify acquirer. (2) Determine acquisition date. (3) Recognise and measure identifiable assets acquired and liabilities assumed (at fair value). (4) Recognise and measure goodwill or bargain purchase. Goodwill = Consideration transferred - Net identifiable assets = 800,000 - 700,000 = N100,000. Entries in A\'s books: Dr Net identifiable assets (individually) N700,000, Dr Goodwill N100,000, Cr Cash/Shares N800,000. Goodwill: not amortised, tested for impairment annually (IAS 36). If consideration < net assets (bargain purchase): gain recognised in P&L after reassessment. Non-controlling interest measured at fair value or proportionate share of net assets.', 'Financial Accounting'),
  tq('tfa98', 'Explain the concept of break-even analysis. A company sells a product for N200 per unit. Variable cost is N120 per unit. Fixed costs are N400,000. Calculate the break-even point in units and in sales value.', 'Break-even point: where total revenue = total costs (zero profit). Contribution per unit = Selling price - Variable cost = 200 - 120 = N80. Break-even (units) = Fixed costs / Contribution per unit = 400,000/80 = 5,000 units. Break-even (sales value) = 5,000 x N200 = N1,000,000. Or: Contribution margin ratio = 80/200 = 40%. BEP (value) = Fixed costs / CMR = 400,000/0.40 = N1,000,000. Margin of safety = (Actual sales - Break-even sales)/Actual sales x 100. If forecast sales = N1,250,000: margin = (1,250,000-1,000,000)/1,250,000 x 100 = 20%. Break-even analysis helps assess risk and target profit.', 'Financial Accounting'),
  tq('tfa99', 'Explain the accounting treatment for share-based payments under IFRS 2. A company grants 1,000 share options to each of 100 employees. Each option vests after 2 years. Fair value of option at grant date is N15. Estimated forfeiture rate is 10%. Show the entries.', 'IFRS 2: share-based payments recognised at fair value. Total expense = 100 employees x 1,000 options x N15 x (1-0.10) = N1,350,000. Vesting period = 2 years. Annual expense = N675,000. Journal each year: Dr Employee expense (P&L) N675,000, Cr Equity reserve (or liability if cash-settled) N675,000. At vesting: adjust for actual forfeitures. If equity-settled: reserve transferred to share capital/premium when options exercised. If lapsed: reserve remains in equity. IFRS 2 applies to all share-based payments including employee share options, share appreciation rights, and share grants. The expense impacts P&L and EPS.', 'Financial Accounting'),
  tq('tfa100', 'Explain the components of the accounting cycle and the process of closing the books at year-end.', 'Accounting cycle steps: (1) Analyse transactions. (2) Journalise (record in journal). (3) Post to ledger accounts. (4) Prepare trial balance. (5) Make adjusting entries (accruals, prepayments, depreciation, bad debts). (6) Prepare adjusted trial balance. (7) Prepare financial statements (trading, P&L, balance sheet). (8) Make closing entries — close temporary accounts (revenues, expenses, drawings) to capital/retained earnings. Revenue accounts debited, expense accounts credited. (9) Prepare post-closing trial balance (only permanent accounts remain). (10) Reverse entries (optional — to simplify next period). Temporary accounts: revenue, expense, drawings/dividends — closed to zero each year. Permanent accounts: assets, liabilities, capital — carried forward.', 'Financial Accounting'),
]
